class DummyPaginator:
    def __init__(
        self,
        *,
        per_page: int,
        match_count: int,
        current_page: int | str | None = None,
    ):
        if current_page is None:
            current_page = 1

        elif isinstance(current_page, str):
            current_page = int(current_page, 10) if current_page.isnumeric() else 1

        self.per_page = per_page
        self.num_pages = math.ceil(match_count / per_page)
        self.match_count = match_count
        self.page_range = range(1, current_page + 2)
        self.current_page = DummyPaginator.clean_page(current_page)

    @staticmethod
    def clean_page(page: str | int | None, max: int | None = None) -> int:
        if page == 'last':
            return max or 1000
        try:
            page = int(page or 1)
        except ValueError:
            page = 1
        if page < 1:
            return 1
        if max and page > max:
            return max
        return page

    def slice(self, search: QuerySet | search.Search) -> QuerySet | search.Search:
        return DummyPaginator.slice_search(search, page=self.current_page, page_size=self.per_page)

    @staticmethod
    def slice_search(
        search: QuerySet | search.Search, *, page: int, page_size: int
    ) -> QuerySet | search.Search:
        bottom = (page - 1) * page_size
        top = page * page_size
        return search[bottom:top]

    @property
    def is_paginated(self) -> bool:
        return self.current_page > 1 or self.match_count == self.per_page


