class OtovoElasticListHandler:
    @classmethod
    def get_document_class(
        cls, *, model: type[OM] | None, document_class: type[Document] | None
    ) -> type[Document]:
        from django_elasticsearch_dsl.registries import registry

        if document_class:
            return document_class
        if model:
            document_classes = registry.get_documents([model])
            if len(document_classes) == 1:
                return document_classes.pop()
            elif len(document_classes) > 1:
                raise ElasticFailure(
                    f'Found multiple Document class for model {model}. '
                    'Specify one of these by setting document_class in the '
                    'view.'
                    f'{", ".join([d.__name__ for d in document_classes])}'
                )
            raise ElasticFailure(f'Could not find Document class for model {model}. ')
        raise ElasticFailure('Missing both document_class and model view attributes.')

    @classmethod
    def get_elastic_search(
        cls, search: search.Search, *, query: query.Query | None, filters: dict[str, Any]
    ) -> search.Search:
        for field, value in filters.items():
            search = search.filter('term', **{field: value})

        if query:
            search = search.query(query)

        return search

    @classmethod
    def get_queryset(cls, *, search_instance: search.Search, ordering: tuple[str]) -> search.Search:
        try:
            return search_instance.sort(*ordering)
        except (ElasticsearchException, HTTPError) as exc:
            document_class = getattr(search_instance, '_doc_type', None) or getattr(
                search_instance, '_model', 'Unknown'
            )

            logger.error(
                'Error while attempting to search on Document class %s',
                document_class,
                exc_info=True,
            )
            raise ElasticFailure(exc) from exc


