```python
def get_ordering(self) -> tuple[str | OrderBy, ...] | str | OrderBy:
    fallback_order = self.get_default_order_tuple()[0]
    ordering = self.request.GET.get(self.order_param, fallback_order)
    default_order = self.get_default_order_tuple()
    _ordering = default_order if ordering in default_order else (ordering, *default_order)

    if self.elastic_enabled:
        return tuple(self.get_elastic_mapped_ordering(o) for o in _ordering)
    return _ordering
